21	// Build a minimal express app with just the health route (no requireAuth — intentional by design)
22	const app = express();
23	app.use(helmet());
24	app.get('/api/health', async (_req: Request, res: Response) => {
25	  try {
26	    await fibaroClient.get('/api/loginStatus', { timeout: 3000 });
27	    res.json({ status: 'ok', fibaro: 'reachable', timestamp: new Date().toISOString() });
28	  } catch {
29	    res.status(503).json({ status: 'degraded', fibaro: 'unreachable', timestamp: new Date().toISOString() });
30	  }
31	});
