33	describe('GET /api/health', () => {
34	  beforeEach(() => {
35	    mockGet.mockReset();
36	  });
37	
38	  it('returns 200 with status ok when Fibaro is reachable', async () => {
39	    mockGet.mockResolvedValueOnce({ data: { status: 'ok' } });
40	    const res = await request(app).get('/api/health');
41	    expect(res.status).toBe(200);
42	    expect(res.body.status).toBe('ok');
43	    expect(res.body.fibaro).toBe('reachable');
44	    expect(res.body.timestamp).toMatch(/^\d{4}-\d{2}-\d{2}T/);
45	    expect(mockGet).toHaveBeenCalledWith('/api/loginStatus', { timeout: 3000 });
46	  });
47	
48	  it('returns 503 with status degraded when Fibaro is unreachable', async () => {
49	    mockGet.mockRejectedValueOnce(new Error('connect ECONNREFUSED'));
50	    const res = await request(app).get('/api/health');
51	    expect(res.status).toBe(503);
52	    expect(res.body.status).toBe('degraded');
53	    expect(res.body.fibaro).toBe('unreachable');
54	    expect(res.body.timestamp).toMatch(/^\d{4}-\d{2}-\d{2}T/);
55	  });
56	
57	  it('response includes Helmet security headers', async () => {
58	    mockGet.mockResolvedValueOnce({ data: {} });
59	    const res = await request(app).get('/api/health');
60	    expect(res.headers['x-content-type-options']).toBe('nosniff');
61	    expect(res.headers['x-frame-options']).toBe('SAMEORIGIN');
62	  });
63	
64	  // Intentional design: /api/health is public and does not require an Authorization header.
65	  // This allows load balancers and monitoring tools to probe the endpoint without credentials.
66	  it('is accessible without an Authorization header (no 401)', async () => {
67	    mockGet.mockResolvedValueOnce({ data: {} });
68	    const res = await request(app).get('/api/health');
69	    expect(res.status).not.toBe(401);
70	    expect(res.status).toBe(200);
71	  });
